mapper.select:
/* SQL ID : AsmtProfIndivDAO.indivStdList 설 명 : 개별 수강생 목록 */ SELECT USR.USER_ID , USR.USERNM , USR.STDNT_NO , DEPT.DEPTNM FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_USER USR ON USR.USER_ID = ATNDLC.USER_ID LEFT JOIN TB_LMS_DEPT DEPT ON DEPT.DEPT_ID = USR.DEPT_ID WHERE ATNDLC.SBJCT_ID = #{sbjctId} AND ATNDLC.AUDITYN = 'N' AND ATNDLC.ATNDLC_STSCD = 'ATNDLC' AND USR.USER_STSCD = 'ACTV'
AND NOT EXISTS ( SELECT 1 FROM TB_LMS_ASMT_SBMSN SBMSN WHERE SBMSN.ASMT_ID = #{asmtId} AND SBMSN.USER_ID = ATNDLC.USER_ID AND SBMSN.DELYN = 'N' )
ORDER BY USR.USERNM
